import{C as e,I as t,L as n,N as r,R as i,X as a,d as o,x as s}from"../chunks/DI_erTYQ.js";import{c}from"../chunks/zudbYdmb.js";import"../chunks/ibwe1TAv.js";import{t as l}from"../chunks/mvW8Je6C.js";import{t as u}from"../chunks/DUc2IljD.js";var d=e(`<h1>Writing YAML from Python</h1> <!> <p>The reverse direction is just as important: sometimes a Python script needs to <em>create</em> a YAML file. Common situations in semiconductor design:</p> <ul><li>After a simulation run, save the resulting power/timing numbers as YAML for the next stage</li> <li>After synthesis, write a report file summarising the area and critical path</li> <li>When generating many test cases, produce one small YAML per test</li></ul> <p>The good news: writing YAML is just as simple as reading it.</p> <hr/> <h2>From dictionary to file: <code>yaml.dump()</code></h2> <p><code>yaml.dump()</code> is the opposite of <code>yaml.safe_load()</code>. You hand it a Python dictionary and a file, and it writes out a clean YAML file.</p> <p>First, install the library (one-time, same as for reading):</p> <pre class="shiki github-light" style="background-color:#fff;color:#24292e" tabindex="0"><code><span class="line"><span style="color:#6F42C1">pip</span><span style="color:#032F62"> install</span><span style="color:#032F62"> pyyaml</span></span></code></pre> <p>A complete write example:</p> <pre class="shiki github-light" style="background-color:#fff;color:#24292e" tabindex="0"><code><span class="line"><span style="color:#D73A49">import</span><span style="color:#24292E"> yaml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E">config </span><span style="color:#D73A49">=</span><span style="color:#005CC5"> dict</span><span style="color:#24292E">(</span></span>
<span class="line"><span style="color:#E36209">    project_name</span><span style="color:#D73A49">=</span><span style="color:#032F62">'My Chip'</span><span style="color:#24292E">,</span></span>
<span class="line"><span style="color:#E36209">    frequency_mhz</span><span style="color:#D73A49">=</span><span style="color:#005CC5">100</span><span style="color:#24292E">,</span></span>
<span class="line"><span style="color:#E36209">    debug_mode</span><span style="color:#D73A49">=</span><span style="color:#005CC5">True</span><span style="color:#24292E">,</span></span>
<span class="line"><span style="color:#24292E">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D73A49">with</span><span style="color:#005CC5"> open</span><span style="color:#24292E">(</span><span style="color:#032F62">'output.yaml'</span><span style="color:#24292E">, </span><span style="color:#032F62">'w'</span><span style="color:#24292E">) </span><span style="color:#D73A49">as</span><span style="color:#24292E"> f:</span></span>
<span class="line"><span style="color:#24292E">    yaml.dump(config, f, </span><span style="color:#E36209">default_flow_style</span><span style="color:#D73A49">=</span><span style="color:#005CC5">False</span><span style="color:#24292E">)</span></span></code></pre> <p>Run it, and the script creates <code>output.yaml</code> in the current folder containing exactly the values you put into the dictionary.</p> <hr/> <h2>The three lines that write YAML</h2> <p>Strip away everything except the essentials:</p> <pre class="shiki github-light" style="background-color:#fff;color:#24292e" tabindex="0"><code><span class="line"><span style="color:#D73A49">import</span><span style="color:#24292E"> yaml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D73A49">with</span><span style="color:#005CC5"> open</span><span style="color:#24292E">(</span><span style="color:#032F62">'output.yaml'</span><span style="color:#24292E">, </span><span style="color:#032F62">'w'</span><span style="color:#24292E">) </span><span style="color:#D73A49">as</span><span style="color:#24292E"> f:</span></span>
<span class="line"><span style="color:#24292E">    yaml.dump(my_data, f, </span><span style="color:#E36209">default_flow_style</span><span style="color:#D73A49">=</span><span style="color:#005CC5">False</span><span style="color:#24292E">)</span></span></code></pre> <p>What each piece does:</p> <ul><li><strong><code>open('output.yaml', 'w')</code></strong> — opens the file for <strong>writing</strong> (the <code>'w'</code> is important; without it Python refuses to overwrite)</li> <li><strong><code>yaml.dump(my_data, f, ...)</code></strong> — writes the Python data into that file as YAML</li> <li><strong><code>default_flow_style=False</code></strong> — tells PyYAML to use the readable multi-line format, not a cramped one-line “flow” style</li></ul> <hr/> <h2>The flow style trap</h2> <p>If you forget <code>default_flow_style=False</code>, PyYAML tries to help by putting everything on one line — something like <code>[project_name: My Chip, frequency_mhz: 100, debug_mode: true]</code> all crammed together inside braces.</p> <p>That is technically valid YAML, but nobody wants to read it. With <code>default_flow_style=False</code>, you get the clean, proper format instead:</p> <!> <p><strong>Rule of thumb: always pass <code>default_flow_style=False</code> unless you explicitly want one-liner output.</strong></p> <hr/> <h2>Going the other way: reading what you wrote</h2> <p>Whatever <code>yaml.dump()</code> writes, <code>yaml.safe_load()</code> can read back. This is how EDA tool chains pass data between stages without writing custom binary formats — each stage speaks plain YAML.</p> <pre class="shiki github-light" style="background-color:#fff;color:#24292e" tabindex="0"><code><span class="line"><span style="color:#D73A49">import</span><span style="color:#24292E"> yaml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D"># Stage 1: write</span></span>
<span class="line"><span style="color:#24292E">results </span><span style="color:#D73A49">=</span><span style="color:#005CC5"> dict</span><span style="color:#24292E">(</span><span style="color:#E36209">area_um2</span><span style="color:#D73A49">=</span><span style="color:#005CC5">12450</span><span style="color:#24292E">, </span><span style="color:#E36209">max_freq_mhz</span><span style="color:#D73A49">=</span><span style="color:#005CC5">1200</span><span style="color:#24292E">)</span></span>
<span class="line"><span style="color:#D73A49">with</span><span style="color:#005CC5"> open</span><span style="color:#24292E">(</span><span style="color:#032F62">'stage1.yaml'</span><span style="color:#24292E">, </span><span style="color:#032F62">'w'</span><span style="color:#24292E">) </span><span style="color:#D73A49">as</span><span style="color:#24292E"> f:</span></span>
<span class="line"><span style="color:#24292E">    yaml.dump(results, f, </span><span style="color:#E36209">default_flow_style</span><span style="color:#D73A49">=</span><span style="color:#005CC5">False</span><span style="color:#24292E">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D"># Stage 2: read</span></span>
<span class="line"><span style="color:#D73A49">with</span><span style="color:#005CC5"> open</span><span style="color:#24292E">(</span><span style="color:#032F62">'stage1.yaml'</span><span style="color:#24292E">) </span><span style="color:#D73A49">as</span><span style="color:#24292E"> f:</span></span>
<span class="line"><span style="color:#24292E">    prev </span><span style="color:#D73A49">=</span><span style="color:#24292E"> yaml.safe_load(f)</span></span>
<span class="line"><span style="color:#005CC5">print</span><span style="color:#24292E">(prev[</span><span style="color:#032F62">'area_um2'</span><span style="color:#24292E">])   </span><span style="color:#6A737D"># 12450</span></span></code></pre> <p>Your YAML file acts as the contract between the two scripts. If someone later wants to inspect or tweak what stage 1 handed off, they can open the YAML file in any text editor — no special tool required.</p> <hr/> <h2>Key takeaways</h2> <ul><li><code>yaml.dump(data, file)</code> turns a Python dictionary into a YAML file</li> <li>Open the file with <code>'w'</code> to allow writing: <code>open('out.yaml', 'w')</code></li> <li>Always pass <code>default_flow_style=False</code> for readable multi-line output</li> <li>Scripts in a pipeline can pass data via YAML files — one writes, the next reads — no special format needed</li></ul> <p>Next, we will see what happens when things go wrong: syntax mistakes in YAML, missing files, and how Python reports them.</p> <hr/> <div class="not-prose" style="margin-top:2rem;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:1rem;"><a style="display:inline-flex;align-items:center;gap:0.5rem;padding:0.65rem 1.25rem;border-radius:8px;font-size:0.82rem;text-decoration:none;border:1px solid var(--color-border);color:var(--color-text-muted);font-family:var(--font-ui);transition:all 0.25s ease;">← Previous</a> <a style="display:inline-flex;align-items:center;gap:0.5rem;padding:0.65rem 1.25rem;border-radius:8px;font-weight:600;font-size:0.85rem;text-decoration:none;background:var(--color-accent);color:white;font-family:var(--font-ui);transition:all 0.25s ease;">Next: Handling YAML Errors →</a></div>`,1);function f(e){let f=[{indent:0,tokens:[{text:`project_name`,type:`key`},{text:`: `,type:`colon`},{text:`"My Chip"`,type:`str`}]},{indent:0,tokens:[{text:`frequency_mhz`,type:`key`},{text:`: `,type:`colon`},{text:`100`,type:`num`}]},{indent:0,tokens:[{text:`debug_mode`,type:`key`},{text:`: `,type:`colon`},{text:`true`,type:`bool`}]}];var p=d(),m=i(n(p),2);l(m,{minutes:6,learn:[`How a script writes a YAML report file after a run`,`How yaml.dump() converts Python values back to YAML text`,`Keeping written reports clean and readable with sort_keys / default_flow_style`]});var h=i(m,44);u(h,{get rows(){return f}});var g=i(h,24),_=t(g),v=i(_,2);a(g),r(()=>{o(_,`href`,`${c??``}/lesson-12`),o(v,`href`,`${c??``}/lesson-14`)}),s(e,p)}export{f as component};